export function getThirdPlaceBracket(qualifiedThirdGroups: string[]) {
  const key = qualifiedThirdGroups
    .map((group) => group.replace(/^3/, "").toUpperCase())
    .sort()
    .join("");

  const bracket = THIRD_PLACE_BRACKETS[key];

  if (!bracket) {
    throw new Error(`No FIFA Annexe C bracket found for third-place combination: ${key}`);
  }

  return bracket;
}

export function getThirdPlaceOpponent(firstGroupSlot: FirstGroupSlot, qualifiedThirdGroups: string[]) {
  return getThirdPlaceBracket(qualifiedThirdGroups).pairings[firstGroupSlot];
}
